clients-loading-state.css:
.clients-loading-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 64px var(--goa-space-m);
  background-color: var(--goa-color-greyscale-white, #ffffff);
}

example.code:
// State for loading
const [isLoading, setIsLoading] = useState(true);
const [data, setData] = useState([]);

// Fetch data on mount
useEffect(() => {
  const fetchData = async () => {
    setIsLoading(true);
    const result = await fetch('/api/items');
    const json = await result.json();
    setData(json);
    setIsLoading(false);
  };
  fetchData();
}, []);

// In table body:
<tbody>
  {isLoading ? (
    // Skeleton rows - create 10 placeholder rows
    [...Array(10)].map((_, i) => (
      <tr key={i} data-grid="row">
        {/* Checkbox cell */}
        <td data-grid="cell" className="goa-table-cell--checkbox">
          <div style={{
            width: '18px',
            height: '18px',
            borderRadius: '4px',
            backgroundColor: 'var(--goa-color-greyscale-200)'
          }} />
        </td>

        {/* Badge cell */}
        <td data-grid="cell">
          <div style={{
            height: '22px',
            width: `${60 + (i % 3) * 15}px`,  // Vary widths for natural look
            borderRadius: '12px',
            backgroundColor: 'var(--goa-color-greyscale-200)'
          }} />
        </td>

        {/* Text cells - vary widths */}
        <td data-grid="cell">
          <div style={{
            height: '14px',
            width: `${50 + (i % 5) * 10}%`,
            borderRadius: '4px',
            backgroundColor: 'var(--goa-color-greyscale-200)'
          }} />
        </td>

        <td data-grid="cell">
          <div style={{
            height: '14px',
            width: `${60 + (i % 4) * 10}%`,
            borderRadius: '4px',
            backgroundColor: 'var(--goa-color-greyscale-200)'
          }} />
        </td>

        <td data-grid="cell">
          <div style={{
            height: '14px',
            width: `${70 + (i % 3) * 10}%`,
            borderRadius: '4px',
            backgroundColor: 'var(--goa-color-greyscale-200)'
          }} />
        </td>

        {/* Action cell */}
        <td data-grid="cell">
          <div style={{
            width: '24px',
            height: '24px',
            borderRadius: '4px',
            backgroundColor: 'var(--goa-color-greyscale-200)'
          }} />
        </td>
      </tr>
    ))
  ) : (
    // Actual data rows
    data.map(item => (
      <tr key={item.id}>...</tr>
    ))
  )}
</tbody>

